import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as t,c as d,e as o}from"./app-b3edeb65.js";const n={},a=o(`<h1 id="锁机制" tabindex="-1"><a class="header-anchor" href="#锁机制" aria-hidden="true">#</a> 锁机制</h1><h1 id="事务" tabindex="-1"><a class="header-anchor" href="#事务" aria-hidden="true">#</a> 事务</h1><blockquote><p>事务概念及四大特性</p></blockquote><p>事务是由一组<code>SQL</code>语句组成的逻辑处理单元，事务具有以下4个属性，通常简称为事务的ACID属性。</p><ul><li>原子性(Atomicity):事务是一个原子操作单元，其对数据的修改，要么全都执行，要么全都不执行。</li><li>一致性(Consistent):在事务开始和完成时，数据都必须保持一致状态。这意味着所有相关的数据规则都必须应用于事务的修改以保持数据的完整性；事务结束时，所有的内部数据结构(如B树索引或双向链表)也都必须是正确的。</li><li>隔离性(Isolation):数据库系统提供一定的隔离机制，保证事务在不受外部并发操作影响的&quot;独立&quot;环境执行。这意味着事务处理过程中的中间状态对外部是不可见的，反之亦然。</li><li>持久性(Durable):事务完成之后，它对于数据的修改是永久性的，即使出现系统故障也能够保持。</li></ul><blockquote><p>并发事务处理带来的问题</p></blockquote><p><strong>更新丢失(Lost Update)</strong></p><p>当两个或多个事务选择同一行，然后基于最初选定的值更新该行时，由于每个事务都不知道其他事务的存在，就会发生丢失更新问题-一最后的更新覆盖了由其他事务所做的更新。</p><p>例如，两个程序员修改同一python文件。每程序员独立地更改其副本，然后保存更改后的副本，这样就覆盖了原始文档。最后保存其更改副本的编辑人员覆盖前一个程序员所做的更改。</p><p>如果在一个程序员完成并提交事务之前，另一个程序员不能访问同一文件，则可避免此问题。</p><p><strong>脏读(Dirty Reads)</strong></p><p>一个事务正在对一条记录做修改，在这个事务完成并提交前，这条记录的数据就处于不一致状态；这时，另一个事务也来读取同一条记录，如果不加控制，第二个事务读取了这些&quot;脏&quot;数据，并据此做进一步的处理，就会产生未提交的数据依赖关系。这种现象被形象地叫做&quot;脏读&quot;。</p><p>一句话:事务A读取到了事务B<strong>已修改但尚未提交</strong>的的数据，还在这个数据基础上做了操作。此时，如果B事务回滚，A读取的数据无效，不符合一致性要求。</p><p><strong>不可重复读(Non-Repeatable Reads)</strong></p><p>一个事务在读取某些数据后的某个时间，再次读取以前读过的数据，却发现其读出的数据已经发生了改变、或某些记录已经被删除了！这种现象就叫做&quot;不可重复读&quot;。</p><p>一句话:事务A读取到了事务B<strong>已经提交</strong>的修改数据，不符合隔离性</p><p><strong>幻读(Phantom Reads)</strong></p><p>一个事务按相同的查询条件重新读取以前检索过的数据，却发现其他事务插入了满足其查询条件的新数据，这种现象就称为&quot;幻读一句话:事务A读取到了事务B体提交的新增数据，不符合隔离性。</p><p>多说一句:幻读和脏读有点类似，脏读是事务B里面修改了数据，幻读是事务B里面新增了数据。</p><blockquote><p>事务隔离级别</p></blockquote><p>&quot;脏读&quot;、&quot;不可重复读&quot;和&quot;幻读&quot;，其实都是数据库读一致性问题，必须由数据库提供一定的事务隔离机制来解决。</p><table><thead><tr><th>读数据一致性及允许的并发副作用隔离级别</th><th>隔离級别</th><th>脏读</th><th>不可重复读</th><th>幻读</th></tr></thead><tbody><tr><td>未提交读(Read uncommitted)</td><td>最低级别，只能保证不读取物理上损坏的数据</td><td>是</td><td>是</td><td>是</td></tr><tr><td>已提交读(Read committed)</td><td>语句级</td><td>否</td><td>是</td><td>是</td></tr><tr><td>可重复读(Repeatable read)</td><td>事务级</td><td>否</td><td>否</td><td>是</td></tr><tr><td>可序列化(Serializable)</td><td>最高级别，事务级</td><td>否</td><td>否</td><td>否</td></tr></tbody></table><p>数据库的事务隔离越严格，并发副作用越小，但付出的代价也就越大，因为事务隔离实质上就是使事务在一定程度上&quot;串行化&quot;进行，这显然与&quot;并发&quot;是矛盾的。同时，不同的应用对读一致性和事务隔离程度的要求也是不同的，比如许多应用对&quot;不可重复读&quot;和&quot;幻读&quot;并不敏感，可能更关心数据并发访问的能力。</p><p>查看当前数据库的事务隔离级别:<code>show variables like&#39;tx_isolation&#39;;</code></p><h1 id="mysql锁" tabindex="-1"><a class="header-anchor" href="#mysql锁" aria-hidden="true">#</a> MySQL锁</h1><h2 id="概述" tabindex="-1"><a class="header-anchor" href="#概述" aria-hidden="true">#</a> 概述</h2><p>锁是计算机协调多个进程或线程并发访问某一资源的机制。<br> 在数据库中，除传统的计算资源(如CPU、RAM、I/O等)的争用以外，数据也是一种供许多用户共享的资源。如何保证数据并发访问的一致性、有效性是所有数据库必须解决的一个问题，锁冲突也是影响数据库并发访问性能的一个重要因素。从这个角度来说，锁对数据库而言显得尤其重要，也更加复杂。</p><p>从对数据操作的类型分:</p><p>读锁(共享锁):针对同一份数据，多个读操作可以同时进行而不会互相影响。</p><p>写锁(排它锁):当前写操作没有完成前，它会阻断其他写锁和读锁。</p><p>从对数据操作的粒度分:表锁、行锁、页锁</p><h2 id="表锁" tabindex="-1"><a class="header-anchor" href="#表锁" aria-hidden="true">#</a> 表锁</h2><p>表锁(偏读):偏向MyISAM存储引擎，开销小，加锁快；无死锁；锁定粒度大，发生锁冲突的概率最高，并发度最低。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 手动增加表锁</span>
lock table 名字 read<span class="token punctuation">(</span>write<span class="token punctuation">)</span>,表名字2 read<span class="token punctuation">(</span>write<span class="token punctuation">)</span>,其它<span class="token punctuation">;</span>
<span class="token comment"># 查看表上加过的锁</span>
show <span class="token function">open</span> tables<span class="token punctuation">;</span>
<span class="token comment"># 解锁</span>
unlock tables<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="案例" tabindex="-1"><a class="header-anchor" href="#案例" aria-hidden="true">#</a> 案例</h3><blockquote><p>对mylock表加read锁(MyISAM存储引擎的读阻塞读例子)</p></blockquote><table><thead><tr><th>session1</th><th>session2</th></tr></thead><tbody><tr><td>获得表mylock的READ锁定: <code>lock table mylock read;</code></td><td>连接终端</td></tr><tr><td>当前session可以查询该表记录:<code>select * from mylock;</code></td><td>其他session也可以查询该表的记录</td></tr><tr><td>当前session不能查询其它没有锁定的表，查询报错</td><td>其他session可以查询或者更新未锁定的表</td></tr><tr><td>当前session中插入或者更新锁定的表都会提示错误</td><td>其他session插入或者更新锁定表<strong>会一直等待</strong>获得锁</td></tr><tr><td>释放锁:<code>unlock tables;</code></td><td>Session2获得锁，插入遇作完成</td></tr></tbody></table><blockquote><p>对mylock表加write锁(MyISAM存储引擎的写阻塞读例子)</p></blockquote><table><thead><tr><th>session1</th><th>session2</th></tr></thead><tbody><tr><td>获得表mylock的READ锁定: <code>lock table mylock write;</code></td><td>待Session1开启写锁后，session2再连接终端</td></tr><tr><td>当前session对锁定表的查询+更新+插入操作都可以执行</td><td>其他session对锁定表的查询被阻塞，需要等待锁被释放；备注:如果可以，语换成不同的id来进行测试，因为mysgl聪明有缓存，第2次的条件会从从缓存取得，影响锁效果演示</td></tr><tr><td>释放锁:<code>unlock tables;</code></td><td>Session2获得锁，查询返回</td></tr></tbody></table><h3 id="表锁分析" tabindex="-1"><a class="header-anchor" href="#表锁分析" aria-hidden="true">#</a> 表锁分析</h3><p>查看哪些表被加锁了</p><div class="language-mysql line-numbers-mode" data-ext="mysql"><pre class="language-mysql"><code>show open tables;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>如何分析表锁定</p><div class="language-mysql line-numbers-mode" data-ext="mysql"><pre class="language-mysql"><code>mysql&gt; show status like &quot;table%&quot;;
+----------------------------+-------+
| Variable_name              | Value |
+----------------------------+-------+
| Table_locks_immediate      | 1     |
| Table_locks_waited         | 0     |
| Table_open_cache_hits      | 288   |
| Table_open_cache_misses    | 26    |
| Table_open_cache_overflows | 0     |
+----------------------------+-------+
5 rows in set (0.00 sec)
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>table_locks_waited</code>和<code>table_locks_immediate</code>两个状态变量记录MySQL内部表级锁定的情况，两个变量说明如下:</p><p><code>Table_locks_immediate</code>:产生表级锁定的次数，表示可以立即获取锁的查询次数，每立即获取锁值加1；</p><p><code>Table_locks_waited</code>:出现表级锁定争用而发生等待的次数(不能立即获取锁的次数，每等待一次锁值加1)，此值高则说明存在着较严重的表级锁争用情况；</p><p>此外，MyISAM的读写锁调度是写优先，这也是MyISAM不适合做写为主表的引擎。因为写锁后，其他线程不能做任何操作，大量的更新会使查询很难得到锁，从而造成永远阻塞。</p><h3 id="小结" tabindex="-1"><a class="header-anchor" href="#小结" aria-hidden="true">#</a> 小结</h3><blockquote><p>读锁 VS 写锁</p></blockquote><p>MyISAM在执行查询语句(SELECT)前，会自动给涉及的所有表加读锁，在执行增删改操作前，会自动给涉及的表加写锁。<br> MySQL的表级锁有两种模式:表共享读锁(Table Read Lock)、表独占写锁(Table Write Lock)</p><table><thead><tr><th>锁类型</th><th>可否兼容</th><th>读锁</th><th>写锁</th></tr></thead><tbody><tr><td>读锁</td><td>是</td><td>是</td><td>否</td></tr><tr><td>写锁</td><td>是</td><td>否</td><td>否</td></tr></tbody></table><p>结论:结合上表，所以对MyISAM表进行操作，会有以下情况:</p><p>1、对MyISAM表的读操作(加读锁)，不会阻塞其他进程对同一表的读请求，但会阻塞对同一表的写请求。只有当读锁释放后，才会执行其它进程的写操作。</p><p>2、对MyISAM表的写操作(加写锁)，会阻塞其他进程对同一表的读和写操作，只有当写锁释放后，才会执行其它进程的读写操作。</p><p>简而言之，就是读锁会阻塞写，但是不会堵塞读。而写锁则会把读和写都堵塞。</p><h2 id="行锁" tabindex="-1"><a class="header-anchor" href="#行锁" aria-hidden="true">#</a> 行锁</h2><p>行锁(偏写):偏向InnoDB存储引擎，开销大，加锁慢；会出现死锁；锁定粒度最小，发生锁冲突的概率最低，并发度也最高。</p><p>InnoDB与MyISAM的最大不同有两点:一是支持事务(TRANSACTION)；二是采用了行级锁</p><h3 id="案例-1" tabindex="-1"><a class="header-anchor" href="#案例-1" aria-hidden="true">#</a> 案例</h3><blockquote><p>建表</p></blockquote><div class="language-mysql line-numbers-mode" data-ext="mysql"><pre class="language-mysql"><code>DROP TABLE IF EXISTS employee;
CREATE TABLE IF NOT EXISTS employee (
    id INT PRIMARY KEY auto_increment,
    name VARCHAR(40),
    money INT
)ENGINE INNODB;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p>插入数据</p></blockquote><div class="language-mysql line-numbers-mode" data-ext="mysql"><pre class="language-mysql"><code>INSERT INTO employee(name, money) VALUES(&#39;1001&#39;, 10000);
INSERT INTO employee(name, money) VALUES(&#39;1002&#39;, 10000);
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p>没有索引,插入不同行数据</p></blockquote><table><thead><tr><th>session1</th><th>session2</th></tr></thead><tbody><tr><td>开启行锁: <code>set autocommit=0;</code></td><td>开启行锁: <code>set autocommit=0;</code></td></tr><tr><td>更新数据，但是没有提交:<code>UPDATE employee SET money = money + 10000 WHERE name = &#39;1001&#39;;</code></td><td>session2被阻塞，只能等待:<code>UPDATE employee SET money = money + 5000 WHERE name = &#39;1002&#39;;</code></td></tr><tr><td>提交更新:<code>commit;</code></td><td>解除阻塞，更新正常进行</td></tr><tr><td></td><td>提交更新:<code>commit;</code></td></tr></tbody></table><p>两边结果相同，且正确。</p><p>但问题是，左侧操作的是 <code>name = &#39;1001&#39;</code> 记录而右侧操作的是 <code>name = &#39;1002&#39;</code> 记录，右侧还是被阻塞了，说明，左侧的更新操作锁住了全表！究其原因，是因为 name 字段上没有索引！</p><p>当 Where 查询条件中的字段没有索引时，更新操作会锁住全表！</p><blockquote><p>有索引，插入不同行数据</p></blockquote><div class="language-mysql line-numbers-mode" data-ext="mysql"><pre class="language-mysql"><code>CREATE INDEX idx_name ON employee(name);
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><table><thead><tr><th>session1</th><th>session2</th></tr></thead><tbody><tr><td>开启行锁: <code>set autocommit=0;</code></td><td>开启行锁: <code>set autocommit=0;</code></td></tr><tr><td>正常更新数据:<code>UPDATE employee SET money = money + 10000 WHERE name = &#39;1001&#39;;</code></td><td>正常更新数据:<code>UPDATE employee SET money = money + 5000 WHERE name = &#39;1002&#39;;</code></td></tr><tr><td>提交更新:<code>commit;</code></td><td>提交更新:<code>commit;</code></td></tr></tbody></table><p>在有索引的情况下，更新不同的行，<code>InnoDB</code> 默认的行锁不会阻塞。</p><blockquote><p>有索引，插入同行数据</p></blockquote><div class="language-mysql line-numbers-mode" data-ext="mysql"><pre class="language-mysql"><code>CREATE INDEX idx_name ON employee(name);
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><table><thead><tr><th>session1</th><th>session2</th></tr></thead><tbody><tr><td>开启行锁: <code>set autocommit=0;</code></td><td>开启行锁: <code>set autocommit=0;</code></td></tr><tr><td>正常更新数据:<code>UPDATE employee SET money = money + 10000 WHERE name = &#39;1001&#39;;</code></td><td>session2被阻塞，只能等待:<code>UPDATE employee SET money = money + 5000 WHERE name = &#39;1002&#39;;</code></td></tr><tr><td>提交更新:<code>commit;</code></td><td>解除阻塞，更新正常进行</td></tr><tr><td></td><td>提交更新:<code>commit;</code></td></tr></tbody></table><p>即使在有索引的情况下，更新相同的行，<code>InnoDB</code> 默认的行锁也会阻塞。</p><blockquote><p>索引失效，插入不同行数据</p></blockquote><table><thead><tr><th>session1</th><th>session2</th></tr></thead><tbody><tr><td>开启行锁: <code>set autocommit=0;</code></td><td>开启行锁: <code>set autocommit=0;</code></td></tr><tr><td>正常更新数据:<code>UPDATE employee SET money = money + 10000 WHERE name = 1001;</code></td><td>session2被阻塞，只能等待:<code>UPDATE employee SET money = money + 5000 WHERE name = &#39;1002&#39;;</code></td></tr><tr><td>提交更新:<code>commit;</code></td><td>解除阻塞，更新正常进行</td></tr><tr><td></td><td>提交更新:<code>commit;</code></td></tr></tbody></table><p>Where 条件中的查询字段虽然有索引，但是索引失效时(本例子中是字符串没有加单引号)，InnoDB 默认的行锁更新操作变为表锁。</p><p>我们看到InnoDB默认的行锁可以使得操作不同行时不会产生相互影响、不会阻塞，从而很好的解决了多事务和并发的问题。但是，那得基于一个前提，即<code>Where</code>条件中使用上了索引；反之，如果没有使用上索引，则是全表扫描、全部阻塞。</p><blockquote><p>间隙锁</p></blockquote><table><thead><tr><th>session1</th><th>session2</th></tr></thead><tbody><tr><td>开启行锁: <code>set autocommit=0;</code></td><td>开启行锁: <code>set autocommit=0;</code></td></tr><tr><td>正常更新数据:<code>UPDATE employee SET money = money + 10000 WHERE name = 1001;</code></td><td>session2被阻塞，只能等待:<code>INSERT INTO employee(id, name, money) VALUES(3, &#39;1003&#39;, 10000);</code></td></tr><tr><td>提交更新:<code>commit;</code></td><td>解除阻塞，更新正常进行</td></tr><tr><td></td><td>提交更新:<code>commit;</code></td></tr></tbody></table><p>当我们用范围条件而不是相等条件检索数据，并请求共享或排他锁时，InnoDB会给符合条件的已有数据记录的索引项加锁；对于键值在条件范围内但并不存在的记录，叫做&quot;间隙(GAP)&quot;，InnoDB也会对这个&quot;间隙&quot;加锁，这种锁机制就是所谓的间隙锁(Next-Key锁)。<br> 因为Query执行过程中通过过范围查找的话，他会锁定整个范围内所有的索引键值，即使这个键值并不存在。<br> 间隙锁有一个比较致命的弱点，就是当锁定一个范围键值之后，即使某些不存在的键值也会被无享的锁定，而造成在锁定的时候无法插入锁定键值范围内的任何数据。在某些场景下这可能会对性能造成很大的危害。</p><blockquote><p>锁定特定行</p></blockquote><div class="language-mysql line-numbers-mode" data-ext="mysql"><pre class="language-mysql"><code>begin;  # 开启事务
select * from table_name where filed=value from update;  # 开启行锁
# 执行逻辑
commit;  # 提交事务
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="行锁分析" tabindex="-1"><a class="header-anchor" href="#行锁分析" aria-hidden="true">#</a> 行锁分析</h3><p>如何分析行锁定</p><div class="language-mysql line-numbers-mode" data-ext="mysql"><pre class="language-mysql"><code>mysql&gt; show status like &#39;innodb_row_lock%&#39;;
+-------------------------------+-------+
| Variable_name                 | Value |
+-------------------------------+-------+
| Innodb_row_lock_current_waits | 0     |
| Innodb_row_lock_time          | 88261 |
| Innodb_row_lock_time_avg      | 22065 |
| Innodb_row_lock_time_max      | 50000 |
| Innodb_row_lock_waits         | 4     |
+-------------------------------+-------+
5 rows in set (0.00 sec)
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>通过检查<code>InnoDB_row_lock</code>状态变量来分析系统上的行锁的争夺情况</p><p>对各个状态量的说明如下:<br><code>Innodb_row_lock_current_waits</code>:当前正在等待锁定的数量；</p><p><code>Innodb_row_lock_time</code>:从系统启动到现在锁定总时间长度；</p><p><code>Innodb_row_lock_time_avg</code>:每次等待所花平均时间；</p><p><code>Innodb_row_lock_time_max</code>:从系统启动到现在等待最常的一次所花的时间；</p><p><code>Innodb_row_lock_waits</code>:系统启动后到现在总共等待的次数；</p><p>对于这5个状态变量，比较重要的主要是:<br><code>Innodb_row_lock_time_avg</code>(等待平均时长)</p><p><code>Innodb_row_lock_waits</code>(等待总次数)</p><p><code>Innodb_row_lock_time</code>(等待总时长)</p><p>尤其是当等待次数很高，而且每次等待时长也不小的时候，我们就需要使用<code>show profile</code>，分析系统中为什么会有如此多的等待，然后根据分析结果着手指定优化计划。</p><h3 id="小结-1" tabindex="-1"><a class="header-anchor" href="#小结-1" aria-hidden="true">#</a> 小结</h3><p>Innodb存储引警由于实现了行级锁定，虽然在锁定机制的实现方面所带来的性能损耗可能比表级锁定会要更高一些，但是在整体并发处理能力方面要远远优于MyISAM的表级锁定的。当系统并发量较高的时候，Innodb的整体性能和MyISAM相比就会有比较明显的优势了。<br> 但是，Innodb的行级锁定同样也有其脆弱的一面，当我们使用不当的时候，可能会让Innodb的整体性能表现不仅不能比MylSAM高，甚至可能会更差。</p><p>优化建议:</p><p>尽可能让所有数据检索都通过索引来完成，避免无索引行锁升级为表锁。</p><p>合理设计索引，尽量缩小锁的范围</p><p>尽可能较少检索条件，避免间隙锁</p><p>尽量控制事务大小，减少锁定资源量和时间长度</p><p>尽可能低级别事务隔离</p><h2 id="页锁" tabindex="-1"><a class="header-anchor" href="#页锁" aria-hidden="true">#</a> 页锁</h2><p>开销和加锁时间界于表锁和行锁之间；</p><p>会出现死锁；</p><p>锁定粒度界于表锁和行锁之间，并发度一般。</p>`,111),s=[a];function i(c,l){return t(),d("div",null,s)}const p=e(n,[["render",i],["__file","锁机制.html.vue"]]);export{p as default};
